import React from "react";
import "./about.css";
import AboutImg from "../../assets/about.jpg";
// import CV from "../../assets/John-Cv.pdf";
import Info from "./Info";

const About = () => {
  return (
    <>
      <section className="about section" id="about">
        <h2 className="section__title">About Me</h2>
        <span className="section__subtitle">My Introduction</span>

        <div className="about__container container grid">
          <img src={AboutImg} alt="Chamika Gayashan" className="about__img" />

          <div className="about__data">
            <Info />

            <p className="about__description">
              Hello, I'm Chamika Gayashan a Java specialist with expertise in
              React JS, HTML/CSS, PHP, and JavaScript, building modern,
              responsive websites. <br /> <br /> Also Social Media Consultant
              elevating brand presence, adept in problem-solving.
            </p>

            <span download="" className="button button--flex">
              {/* <a download="" href={CV} className="button button--flex"> */}
              Download CV
              
            </span>
          </div>
        </div>
      </section>
    </>
  );
};

export default About;
